// Define the trait for the dependency
trait EmailSender {
    fn send(&self, to: &str, subject: &str, body: &str) -> Result<(), String>;
}

// Real implementation
struct SmtpSender {
    host: String,
}

impl EmailSender for SmtpSender {
    fn send(&self, to: &str, subject: &str, _body: &str) -> Result<(), String> {
        println!("Sending via {}: '{}' to {}", self.host, subject, to);
        Ok(())
    }
}

// The service that uses the dependency
struct UserService<E: EmailSender> {
    email_sender: E,
}

impl<E: EmailSender> UserService<E> {
    fn new(email_sender: E) -> Self {
        UserService { email_sender }
    }

    fn register_user(&self, name: &str, email: &str) -> Result<(), String> {
        // Business logic...
        self.email_sender.send(
            email,
            "Welcome!",
            &format!("Hello {}, welcome!", name),
        )?;
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::cell::RefCell;

    // Mock that records calls
    struct MockEmailSender {
        sent: RefCell<Vec<(String, String, String)>>,
        should_fail: bool,
    }

    impl MockEmailSender {
        fn new() -> Self {
            MockEmailSender {
                sent: RefCell::new(Vec::new()),
                should_fail: false,
            }
        }

        fn failing() -> Self {
            MockEmailSender {
                sent: RefCell::new(Vec::new()),
                should_fail: true,
            }
        }

        fn sent_count(&self) -> usize {
            self.sent.borrow().len()
        }
    }

    impl EmailSender for MockEmailSender {
        fn send(&self, to: &str, subject: &str, body: &str) -> Result<(), String> {
            if self.should_fail {
                return Err("Send failed".to_string());
            }
            self.sent.borrow_mut().push((
                to.to_string(),
                subject.to_string(),
                body.to_string(),
            ));
            Ok(())
        }
    }

    #[test]
    fn test_register_sends_email() {
        let mock = MockEmailSender::new();
        let service = UserService::new(mock);

        service.register_user("Alice", "alice@test.com").unwrap();

        assert_eq!(service.email_sender.sent_count(), 1);
    }

    #[test]
    fn test_register_handles_send_failure() {
        let mock = MockEmailSender::failing();
        let service = UserService::new(mock);

        let result = service.register_user("Alice", "alice@test.com");
        assert!(result.is_err());
    }
}

// Cargo.toml: [dev-dependencies] mockall = "0.13"

use mockall::automock;

#[automock]
trait Database {
    fn get_user(&self, id: u64) -> Option<String>;
    fn save_user(&self, id: u64, name: &str) -> Result<(), String>;
}

fn greet_user(db: &dyn Database, id: u64) -> String {
    match db.get_user(id) {
        Some(name) => format!("Hello, {}!", name),
        None => "User not found".to_string(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_greet_existing_user() {
        let mut mock = MockDatabase::new();
        mock.expect_get_user()
            .with(mockall::predicate::eq(42))
            .returning(|_| Some("Alice".to_string()));

        let greeting = greet_user(&mock, 42);
        assert_eq!(greeting, "Hello, Alice!");
    }

    #[test]
    fn test_greet_missing_user() {
        let mut mock = MockDatabase::new();
        mock.expect_get_user()
            .returning(|_| None);

        let greeting = greet_user(&mock, 99);
        assert_eq!(greeting, "User not found");
    }
}
